type WorkflowStepStatus =
  | 'pending'
  | 'running'
  | 'completed'
  | 'failed'
  | 'blocked'
  | 'cancelled';

type WorkflowStep = {
  id: string;
  label: string;
  description?: string;
  status: WorkflowStepStatus;
  startedAt?: number;
  endedAt?: number;
  toolName?: string;
  groupId?: string;
};

type WorkflowRun = {
  sessionId: string;
  phase: string;
  steps: WorkflowStep[];
  requiresAction: boolean;
  artifacts: Array<{ id: string; kind: 'file' | 'code' | 'chart'; title: string }>;
};

